public int secondHighest(String s) {
    int largest = -1, second_largest = -1;
    for (char c : s.toCharArray()) {
        if (Character.isDigit(c)) {
            int d = c - '0';
            if (d > largest) {
                second_largest = largest;
                largest = d;
            } else if (d < largest && d > second_largest) {
                second_largest = d;
            }
        }
    }
    return second_largest;
}
